  import sailpoint.object.Identity;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  import sailpoint.api.ObjectUtil;
  import sailpoint.object.TaskResult; 
  import sailpoint.tools.Message;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  
  Log logger = LogFactory.getLog("rule.update.TNNASministry");

  int count = 0;
  List processedIdentities = new ArrayList();
  
  
  QueryOptions qo = new QueryOptions();
  qo.add(Filter.eq("ministry","TNNAS - St. Thomas Health"));
  qo.setCloneResults(true);

  Iterator it = context.search(Identity.class, qo);
  while (null!=it && it.hasNext()){
    try{

      Identity id = it.next();
      if(id != null){
        processedIdentities.add(id.getName());

        id.setAttribute("ministry","Saint Thomas Health Svcs-TN");
        context.saveObject(id);
        ObjectUtil.unlockIdentity(context, id);
        count++;

        if(count%100 == 0){
          context.commitTransaction();
        }
      }
    }

    catch(Exception exp){
      logger.error("Error in processing "+exp.getMessage());
      taskResult.setCompletionStatus(TaskResult.CompletionStatus.Error);
      taskResult.addMessage(Message.error("Error in processing "+exp.getMessage()));
    }
  }

  context.commitTransaction();
  Util.flushIterator(it);

  if(!Util.isEmpty(processedIdentities)){

    String resultMsg = "Total processed identities : "+processedIdentities+" count : "+count;
    logger.debug(resultMsg);
    taskResult.addMessage(Message.info(resultMsg,null));
  }
  
  return "Success";
